@startuml class-diagram-entities title Diagram klas – warstwa encji JPA (repozytorium)
skinparam classAttributeIconSize 0 skinparam classFontStyle bold skinparam backgroundColor #FAFAFA skinparam class { BackgroundColor #EEF2FF BorderColor #6366F1 ArrowColor #6366F1 }
package "pl.javasolutions.apps.repository.model" {
class BicycleEntity { - id : Long <<PK>> - brand : String - model : String - frameNumber : String <<unique>> - ownerName : String - ownerPhone : String -- + getId() : Long + getBrand() : String + getModel() : String + getFrameNumber() : String + getOwnerName() : String + getOwnerPhone() : String + getRepairOrders() : List<RepairOrderEntity> }
class MechanicEntity { - id : Long <<PK>> - firstName : String - lastName : String - specialization : String - hiredAt : LocalDate - email : String <<unique>> -- + getId() : Long + getFirstName() : String + getLastName() : String + getSpecialization() : String + getHiredAt() : LocalDate + getEmail() : String + getRepairOrders() : List<RepairOrderEntity> }
class RepairOrderEntity { - id : Long <<PK>> - description : String - status : String - receivedAt : LocalDateTime - completedAt : LocalDateTime - estimatedCost : BigDecimal -- + getId() : Long + getDescription() : String + getStatus() : String + getReceivedAt() : LocalDateTime + getCompletedAt() : LocalDateTime + getEstimatedCost() : BigDecimal + getBicycle() : BicycleEntity + getMechanic() : MechanicEntity + getRepairSteps() : List<RepairStepEntity> + getParts() : List<PartEntity> }
class RepairStepEntity { - id : Long <<PK>> - description : String - stepOrder : Integer - durationMinutes : Integer -- + getId() : Long + getDescription() : String + getStepOrder() : Integer + getDurationMinutes() : Integer + getRepairOrder() : RepairOrderEntity }
class PartEntity { - id : Long <<PK>> - name : String - manufacturer : String - price : BigDecimal -- + getId() : Long + getName() : String + getManufacturer() : String + getPrice() : BigDecimal + getRepairOrders() : List<RepairOrderEntity> } }
' Relacje JPA BicycleEntity "1" o-- "0..*" RepairOrderEntity : repairOrders\n(OneToMany, CascadeALL) MechanicEntity "1" o-- "0..*" RepairOrderEntity : repairOrders\n(OneToMany, CascadeALL) RepairOrderEntity "1" *-- "0..*" RepairStepEntity : repairSteps\n(OneToMany, CascadeALL) RepairOrderEntity "0..*" -- "0..*" PartEntity : parts\n(ManyToMany via repair_order_part)
note bottom of RepairOrderEntity Tabela łącząca: repair_order_part (repair_order_id, part_id) end note
@enduml

@startuml class-diagram-entities title Diagram klas – warstwa encji JPA (repozytorium)
skinparam classAttributeIconSize 0 skinparam classFontStyle bold skinparam backgroundColor #FAFAFA skinparam class { BackgroundColor #EEF2FF BorderColor #6366F1 ArrowColor #6366F1 }
package "pl.javasolutions.apps.repository.model" {
class BicycleEntity <<Entity>> { - id : Long - brand : String - model : String - frameNumber : String - ownerName : String - ownerPhone : String - repairOrders : List<RepairOrderEntity> }
class MechanicEntity <<Entity>> { - id : Long - firstName : String - lastName : String - specialization : String - hiredAt : LocalDate - email : String - repairOrders : List<RepairOrderEntity> }
class RepairOrderEntity <<Entity>> { - id : Long - description : String - status : String - receivedAt : LocalDateTime - completedAt : LocalDateTime - estimatedCost : BigDecimal - bicycle : BicycleEntity - mechanic : MechanicEntity - repairSteps : List<RepairStepEntity> - parts : List<PartEntity> }
class RepairStepEntity <<Entity>> { - id : Long - description : String - stepOrder : Integer - durationMinutes : Integer - repairOrder : RepairOrderEntity }
class PartEntity <<Entity>> { - id : Long - name : String - manufacturer : String - price : BigDecimal - repairOrders : List<RepairOrderEntity> } }
BicycleEntity "1" o-- "0..*" RepairOrderEntity : OneToMany MechanicEntity "1" o-- "0..*" RepairOrderEntity : OneToMany RepairOrderEntity "1" *-- "0..*" RepairStepEntity : OneToMany (cascade ALL) RepairOrderEntity "0..*" -- "0..*" PartEntity : ManyToMany\n(via repair_order_part)
@enduml
